const express = require('express');
const jwt = require('jsonwebtoken');

const jwtVerificationMiddleware = (req, res, next) => {
  const token = req.headers['authorization']?.split(' ')[1];
  if (!token) {
    return res.status(401).json({ error: 'Access token is missing or invalid' });
  }

  try {
    const secretKey = 'your-strong-secret-key'; // Ensure this is a strong, securely stored key
    const decoded = jwt.verify(token, secretKey, {
      algorithms: ['HS256'], // Explicitly specify allowed algorithms
      maxAge: '1h' // Ensure tokens are not valid indefinitely
    });

    // Attach user info to the request
    req.user = {
      id: decoded.id,
      email: decoded.email
    };

    next();
  } catch (err) {
    return res.status(401).json({ error: 'Token verification failed' });
  }
};

const app = express();
app.use(jwtVerificationMiddleware);

app.get('/protected', (req, res) => {
  res.json({ message: 'This is a protected route', user: req.user });
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});